import "dotenv/config";
import { defineConfig } from "prisma/config";

// ──────────────────────────────────────────────────────────────────────────────
// ARQUITECTURA MULTI-TENANT
//
// Este proyecto usa DOS esquemas de Prisma:
//
//  1. prisma/schema.prisma   → Esquema POR TENANT (BD propia de cada entidad)
//     - Se migra una vez por cada nueva BD creada para un tenant
//     - DATABASE_URL apunta a la BD del tenant en desarrollo
