// ──────────────────────────────────────────────────────────────────────────────

export default defineConfig({
  // Esquema por-tenant (aplica a la BD del tenant de desarrollo)
  schema: "prisma/schema.prisma",
  migrations: {
    path: "prisma/migrations",
    seed: "npx tsx prisma/seed.ts",
  },
  datasource: {
    url: process.env["DATABASE_URL"],
  },
});
